ps.pstext:
if !IsFeatureImplemented(FEAT_SME_F8F16) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let n : integer = UInt(Zn);
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off3::'0');
let nreg : integer{} = 1;

if !IsFeatureImplemented(FEAT_SME_F8F16) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let n : integer = UInt(Zn);
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off2::'0');
let nreg : integer{} = 2;

if !IsFeatureImplemented(FEAT_SME_F8F16) then EndOfDecode(Decode_UNDEF); end;
let v : integer = UInt('010'::Rv);
let n : integer = UInt(Zn);
let m : integer = UInt('0'::Zm);
let offset : integer = UInt(off2::'0');
let nreg : integer{} = 4;

CheckFPMREnabled();
CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV 16;
let vectors : integer = VL DIV 8;
let vstride : integer = vectors DIV nreg;
let vbase : bits(32) = X{}(v);
var vec : integer = (UInt(vbase) + offset) MOD vstride;
var result : bits(VL);
vec = vec - (vec MOD 2);

for r = 0 to nreg-1 do
    let op1 : bits(VL) = Z{}((n+r) MOD 32);
    let op2 : bits(VL) = Z{}(m);
    for i = 0 to 1 do
        let op3 : bits(VL) = ZAvector{}(vec + i);
        for e = 0 to elements-1 do
            let elem1 : bits(8) = op1[(2 * e + i)*:(8)];
            let elem2 : bits(8) = op2[(2 * e + i)*:(8)];
            let elem3 : bits(16) = op3[e*:(16)];
            result[e*:(16)] = FP8MulAddFP{16}(elem3, elem1, elem2,
                                                    FPCR(), FPMR());
        end;
        ZAvector{VL}(vec + i) = result;
    end;
    vec = vec + vstride;
end;
